import React, { useState } from 'react';
import './style.css'; 

function App() {
  const [currentPage, setCurrentPage] = useState("home");

  function changePage (newPage) {
    setCurrentPage(newPage);
  };

  return (
    <div>
      <div id="navmenu">
        <img id="pfp" src="https://media2.giphy.com/media/lpsk0I64u1QBzjBvbp/200w.gif" alt="" draggable="false" />
        <ButtonBar changePage={changePage} /> 
      </div>
      <div id={currentPage == "blog" ? "" : "content"} style={currentPage == "blog" ? {} : { paddingLeft: '2%', paddingRight: '2%' }}>
        <MainAppContent page={currentPage} />
      </div>
    </div>
  );
}

