function ShieldsTile(props) {
  if (props.link === undefined) {
    return (
      <img src={props.shieldslink} alt="" style={{ borderRadius: '20px', height: '35px', padding: '5px' }} />
    );
  } else {
    return (
      <a href={props.link} target="_blank" rel="noreferrer">
        <img src={props.shieldslink} alt="" style={{ borderRadius: '20px', height: '35px', padding: '5px' }} />
      </a>
    );
  }
}


function BlogPost(props) {
  const [isVisible, setIsVisible] = useState(false);

  const toggleVisibility = () => {
    setIsVisible(!isVisible);
  };
    return (
      <div id="content" style={{ paddingLeft: '2%', paddingRight: '2%', paddingBlock: '1%' }}>
        <h2 onClick={toggleVisibility} style={{ cursor: 'pointer' }}>
          {props.postName}
        </h2>
        {isVisible && (
          <div>
            {props.postContent}
          </div>
        )}
        
      </div>
    );
}



export default App;
